mapper.select:
SELECT id, resource_type, title, description, link, skills_json, level_tag, difficulty_tag,
       location_tag, category_tag, time_range_tag, duration_text, created_at, updated_at
FROM resources

    resource_type = #{resourceType}

        AND level_tag = #{levelTag}


        AND difficulty_tag = #{difficultyTag}


        AND location_tag = #{locationTag}


        AND category_tag = #{categoryTag}


        AND time_range_tag = #{timeRangeTag}


ORDER BY updated_at DESC, id DESC
